+    assert_eq!(serde_json::to_string(&AssumptionOrigin::PolicyInherited).unwrap(), "\"PolicyInherited\"");
+    assert_eq!(serde_json::to_string(&AssumptionOrigin::Inferred).unwrap(), "\"Inferred\"");
+}
+
+#[test]
