+}
+
+// ── MonitorKind ────────────────────────────────────────────────────────
+
+#[test]
+fn monitor_kind_debug_distinct() {
+    let kinds = [
+        MonitorKind::Threshold,
+        MonitorKind::Drift,
+        MonitorKind::Coverage,
+        MonitorKind::Invariant,
+        MonitorKind::Budget,
+    ];
+    let mut dbgs = BTreeSet::new();
+    for k in &kinds {
+        dbgs.insert(format!("{k:?}"));
+    }
