+}
+
+#[test]
+fn monitor_kind_serde_roundtrip_all() {
+    for k in [
+        MonitorKind::Threshold,
+        MonitorKind::Drift,
+        MonitorKind::Coverage,
+        MonitorKind::Invariant,
+        MonitorKind::Budget,
+    ] {
