+
+// ── DemotionRecord ─────────────────────────────────────────────────────
+
+#[test]
+fn demotion_record_json_fields() {
+    let rec = DemotionRecord {
+        record_id: "dem-0".to_string(),
+        assumption_id: "a-1".to_string(),
+        evidence: FalsificationEvidence {
+            assumption_id: "a-1".to_string(),
