+    SplitBenchmarkMetrics {
+        throughput_ops_per_sec: throughput,
+        latency_ns: LatencyStatsNs {
+            p50_ns: p50,
+            p95_ns: p95,
+            p99_ns: p99,
+        },
+        peak_rss_delta_bytes: rss,
+    }
