+fn promotion_receipt() -> ReplacementReceipt {
+    let artifacts = vec![ValidationArtifactRef {
+        kind: ValidationArtifactKind::EquivalenceResult,
+        artifact_digest: "equiv-enrich".to_string(),
+        passed: true,
+        summary: "passed".to_string(),
